package controllers.amateur;

import controllers.MainFX;
import entities.User;
import entities.Evenement;
import entities.Ticket;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Node;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.StackPane;

import java.io.IOException;
import java.net.URL;
import java.util.Objects;

public class AmateurMainController {

    private static final String AMATEUR_STYLESHEET = "/views/styles/amateur-theme.css";

    @FXML
    private BorderPane rootPane;

    @FXML
    private StackPane amateurContentArea;

    @FXML
    private NavbarAmateurController navbarIncludeController;

    @FXML
    private SidebarAmateurController sidebarIncludeController;

    @FXML
    private MiniAudioPlayerController miniAudioPlayerIncludeController;

    private Evenement selectedEvent;

    @FXML
    public void initialize() {
        applyStylesheet();
        navbarIncludeController.setNavigationHandler(this::onNavigate);
        navbarIncludeController.setThemeHandler(this::applyTheme);

        User connectedUser = MainFX.getAuthenticatedUser();
        if (connectedUser != null) {
            sidebarIncludeController.setUser(connectedUser);
        }

        sidebarIncludeController.setNavigationHandler(this::onNavigate);
        miniAudioPlayerIncludeController.setNavigationHandler(this::onNavigate);

        onNavigate("feed");
    }

    private void onNavigate(String route) {
        navbarIncludeController.setActiveRoute(route);
        sidebarIncludeController.setActiveItem(route);
        miniAudioPlayerIncludeController.setVisibleForRoute(route);

        Object controller = loadAmateurView(route, resolveRoute(route));
        configureLoadedController(controller);
    }

    public void openEventDetail(Evenement event) {
        this.selectedEvent = event;
        onNavigate("event-detail");
    }

    public void onTicketPurchased(Ticket ticket) {
        // Handle post-purchase actions, e.g. show confirmation, update UI, etc.
        onNavigate("payment-success");
    }

    private String resolveRoute(String route) {
        return switch (route) {
            case "feed", "feed-peintures", "feed-sculptures", "feed-photos", "feed-recommandations" -> "/views/amateur/Feed.fxml";
            case "favoris" -> "/views/amateur/Favoris.fxml";
            case "evenements" -> "/views/amateur/Evenements.fxml";
            case "event-detail" -> "/views/amateur/EventDetail.fxml";
            case "payment-success" -> "/views/amateur/PaymentSuccess.fxml";
            case "bibliotheque" -> "/views/amateur/Bibliotheque.fxml";
            case "book-reader" -> "/views/amateur/BookReader.fxml";
            case "musique" -> "/views/amateur/Musique.fxml";
            case "reclamations" -> "/views/amateur/Reclamations.fxml";
            case "reclamation-detail" -> "/views/amateur/ReclamationDetail.fxml";
            case "edit-profile" -> "/views/amateur/EditProfile.fxml";
            default -> "/views/amateur/Feed.fxml";
        };
    }

    private void applyTheme(boolean darkMode) {
        if (darkMode) {
            if (!rootPane.getStyleClass().contains("dark-mode")) {
                rootPane.getStyleClass().add("dark-mode");
            }
        } else {
            rootPane.getStyleClass().remove("dark-mode");
        }
    }

    private void applyStylesheet() {
        URL stylesheet = Objects.requireNonNull(getClass().getResource(AMATEUR_STYLESHEET), "Missing stylesheet: " + AMATEUR_STYLESHEET);
        String stylesheetUrl = stylesheet.toExternalForm();
        if (!rootPane.getStylesheets().contains(stylesheetUrl)) {
            rootPane.getStylesheets().add(stylesheetUrl);
        }
    }

    private Object loadAmateurView(String route, String fxmlPath) {
        try {
            URL resource = Objects.requireNonNull(getClass().getResource(fxmlPath), "FXML not found: " + fxmlPath);
            FXMLLoader loader = new FXMLLoader(resource);
            Node page = loader.load();

            Object controller = loader.getController();
            if (controller instanceof FeedController feedController) {
                feedController.setRouteFilter(route);
            }

            amateurContentArea.getChildren().setAll(page);
            return controller;
        } catch (IOException e) {
            throw new IllegalStateException("Failed to load amateur page: " + fxmlPath, e);
        }
    }

    private void configureLoadedController(Object controller) {
        if (controller instanceof EventsfrontController eventsController) {
            eventsController.setDetailNavigationHandler(this::openEventDetail);
        } else if (controller instanceof EventDetailController detailController) {
            detailController.setEvent(selectedEvent);
            detailController.setPurchaseHandler(this::onTicketPurchased);
            detailController.setBackHandler(() -> onNavigate("evenements"));
        }
    }
}

package controllers.amateur;

import controllers.MainFX;
import entities.User;
import entities.Evenement;
import entities.Ticket;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Node;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.StackPane;

import java.io.IOException;
import java.net.URL;
import java.util.Objects;

public class AmateurMainController {

    private static final String AMATEUR_STYLESHEET = "/views/styles/amateur-theme.css";

    @FXML
    private BorderPane rootPane;

    @FXML
    private StackPane amateurContentArea;

    @FXML
    private NavbarAmateurController navbarIncludeController;

    @FXML
    private SidebarAmateurController sidebarIncludeController;

    @FXML
    private MiniAudioPlayerController miniAudioPlayerIncludeController;

    private Evenement selectedEvent;

    @FXML
    public void initialize() {
        applyStylesheet();
        navbarIncludeController.setNavigationHandler(this::onNavigate);
        navbarIncludeController.setThemeHandler(this::applyTheme);

        User connectedUser = MainFX.getAuthenticatedUser();
        if (connectedUser != null) {
            navbarIncludeController.setUser(connectedUser);
            sidebarIncludeController.setUser(connectedUser);
        } else {
            navbarIncludeController.setUser(null);
        }

        sidebarIncludeController.setNavigationHandler(this::onNavigate);
        miniAudioPlayerIncludeController.setNavigationHandler(this::onNavigate);

        onNavigate("feed");
    }

    private void onNavigate(String route) {
        navbarIncludeController.setActiveRoute(route);
        sidebarIncludeController.setActiveItem(route);
        miniAudioPlayerIncludeController.setVisibleForRoute(route);

        Object controller = loadAmateurView(route, resolveRoute(route));
        configureLoadedController(controller);
    }

    public void openEventDetail(Evenement event) {
        this.selectedEvent = event;
        onNavigate("event-detail");
    }

    public void onTicketPurchased(Ticket ticket) {
        // Handle post-purchase actions, e.g. show confirmation, update UI, etc.
        onNavigate("payment-success");
    }

    private String resolveRoute(String route) {
        return switch (route) {
            case "feed", "feed-peintures", "feed-sculptures", "feed-photos", "feed-recommandations" -> "/views/amateur/Feed.fxml";
            case "favoris" -> "/views/amateur/Favoris.fxml";
            case "evenements" -> "/views/amateur/Evenements.fxml";
            case "event-detail" -> "/views/amateur/EventDetail.fxml";
            case "payment-success" -> "/views/amateur/PaymentSuccess.fxml";
            case "bibliotheque" -> "/views/amateur/Bibliotheque.fxml";
            case "book-reader" -> "/views/amateur/BookReader.fxml";
            case "musique" -> "/views/amateur/Musique.fxml";
            case "reclamations" -> "/views/amateur/Reclamations.fxml";
            case "reclamation-detail" -> "/views/amateur/ReclamationDetail.fxml";
            case "edit-profile" -> "/views/amateur/EditProfile.fxml";
            default -> "/views/amateur/Feed.fxml";
        };
    }

    private void applyTheme(boolean darkMode) {
        if (darkMode) {
            if (!rootPane.getStyleClass().contains("dark-mode")) {
                rootPane.getStyleClass().add("dark-mode");
            }
        } else {
            rootPane.getStyleClass().remove("dark-mode");
        }
    }

    private void applyStylesheet() {
        URL stylesheet = Objects.requireNonNull(getClass().getResource(AMATEUR_STYLESHEET), "Missing stylesheet: " + AMATEUR_STYLESHEET);
        String stylesheetUrl = stylesheet.toExternalForm();
        if (!rootPane.getStylesheets().contains(stylesheetUrl)) {
            rootPane.getStylesheets().add(stylesheetUrl);
        }
    }

    private Object loadAmateurView(String route, String fxmlPath) {
        try {
            URL resource = Objects.requireNonNull(getClass().getResource(fxmlPath), "FXML not found: " + fxmlPath);
            FXMLLoader loader = new FXMLLoader(resource);
            Node page = loader.load();

            Object controller = loader.getController();
            if (controller instanceof FeedController feedController) {
                feedController.setRouteFilter(route);
            }

            amateurContentArea.getChildren().setAll(page);
            return controller;
        } catch (IOException e) {
            throw new IllegalStateException("Failed to load amateur page: " + fxmlPath, e);
        }
    }

    private void configureLoadedController(Object controller) {
        if (controller instanceof EventsfrontController eventsController) {
            eventsController.setDetailNavigationHandler(this::openEventDetail);
        } else if (controller instanceof EventDetailController detailController) {
            detailController.setEvent(selectedEvent);
            detailController.setPurchaseHandler(this::onTicketPurchased);
            detailController.setBackHandler(() -> onNavigate("evenements"));
        }
    }
}

package controllers.amateur;

import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.MenuButton;
import javafx.stage.Stage;

import java.io.IOException;
import java.net.URL;
import java.util.Objects;
import java.util.function.Consumer;

public class NavbarAmateurController {

    @FXML
    private Button anchorButton;

    @FXML
    private Button notificationsButton;

    @FXML
    private MenuButton oeuvresButton;

    @FXML
    private Button bibliothequeButton;

    @FXML
    private Button musiqueButton;

    private Consumer<String> navigationHandler;
    private Consumer<Boolean> themeHandler;

    public void setNavigationHandler(Consumer<String> navigationHandler) {
        this.navigationHandler = navigationHandler;
    }

    public void setThemeHandler(Consumer<Boolean> themeHandler) {
        this.themeHandler = themeHandler;
    }

    public void setActiveRoute(String route) {
        oeuvresButton.getStyleClass().remove("active");
        bibliothequeButton.getStyleClass().remove("active");
        musiqueButton.getStyleClass().remove("active");

        if (route.startsWith("feed")) {
            oeuvresButton.getStyleClass().add("active");
        } else if ("bibliotheque".equals(route) || "book-reader".equals(route)) {
            bibliothequeButton.getStyleClass().add("active");
        } else if ("musique".equals(route)) {
            musiqueButton.getStyleClass().add("active");
        }
    }

    @FXML
    private void onFeedClick() {
        navigate("feed");
    }

    @FXML
    private void onFeedPeinturesClick() {
        navigate("feed-peintures");
    }

    @FXML
    private void onFeedSculpturesClick() {
        navigate("feed-sculptures");
    }

    @FXML
    private void onFeedPhotosClick() {
        navigate("feed-photos");
    }

    @FXML
    private void onFeedRecommendationsClick() {
        navigate("feed-recommandations");
    }

    @FXML
    private void onBibliothequeClick() {
        navigate("bibliotheque");
    }

    @FXML
    private void onMusiqueClick() {
        navigate("musique");
    }

    @FXML
    private void onThemeLight() {
        if (themeHandler != null) {
            themeHandler.accept(false);
        }
    }

    @FXML
    private void onThemeDark() {
        if (themeHandler != null) {
            themeHandler.accept(true);
        }
    }

    @FXML
    private void onNotificationsClick() {
        notificationsButton.setText("!!");
    }

    @FXML
    private void onSwitchToAdminView() {
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    @FXML
    private void onSwitchToArtistView() {
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    @FXML
    private void onSwitchToAmateurView() {
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

    @FXML
    private void onLogoutClick() {
        // Placeholder for login redirection.
    }

    private void navigate(String route) {
        if (navigationHandler != null) {
            navigationHandler.accept(route);
        }
    }

    private void switchScene(String fxmlPath, String stylesheetPath, String title) {
        Stage stage = (Stage) anchorButton.getScene().getWindow();
        try {
            FXMLLoader loader = new FXMLLoader(getClass().getResource(fxmlPath));
            Parent root = loader.load();
            Scene scene = new Scene(root);
            URL stylesheet = Objects.requireNonNull(getClass().getResource(stylesheetPath), "Missing stylesheet");
            scene.getStylesheets().add(stylesheet.toExternalForm());
            stage.setTitle(title);
            stage.setScene(scene);
            stage.show();
        } catch (IOException e) {
            throw new IllegalStateException("Failed to switch scene: " + fxmlPath, e);
        }
    }
}

package controllers.amateur;

import controllers.MainFX;
import entities.User;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.MenuButton;
import javafx.stage.Stage;

import java.io.IOException;
import java.net.URL;
import java.util.Objects;
import java.util.function.Consumer;

public class NavbarAmateurController {

    @FXML
    private Button anchorButton;

    @FXML
    private Button notificationsButton;

    @FXML
    private MenuButton oeuvresButton;

    @FXML
    private Button bibliothequeButton;

    @FXML
    private Button musiqueButton;

    @FXML
    private MenuButton userMenuButton;

    private Consumer<String> navigationHandler;
    private Consumer<Boolean> themeHandler;

    public void setNavigationHandler(Consumer<String> navigationHandler) {
        this.navigationHandler = navigationHandler;
    }

    public void setThemeHandler(Consumer<Boolean> themeHandler) {
        this.themeHandler = themeHandler;
    }

    public void setUser(User user) {
        if (userMenuButton == null) {
            return;
        }
        if (user == null) {
            userMenuButton.setText("Compte");
            return;
        }

        String prenom = user.getPrenom() == null ? "" : user.getPrenom().trim();
        String nom = user.getNom() == null ? "" : user.getNom().trim();
        String fullName = (prenom + " " + nom).trim();
        userMenuButton.setText(fullName.isEmpty() ? "Compte" : fullName);
    }

    public void setActiveRoute(String route) {
        oeuvresButton.getStyleClass().remove("active");
        bibliothequeButton.getStyleClass().remove("active");
        musiqueButton.getStyleClass().remove("active");

        if (route.startsWith("feed")) {
            oeuvresButton.getStyleClass().add("active");
        } else if ("bibliotheque".equals(route) || "book-reader".equals(route)) {
            bibliothequeButton.getStyleClass().add("active");
        } else if ("musique".equals(route)) {
            musiqueButton.getStyleClass().add("active");
        }
    }

    @FXML
    private void onFeedClick() {
        navigate("feed");
    }

    @FXML
    private void onFeedPeinturesClick() {
        navigate("feed-peintures");
    }

    @FXML
    private void onFeedSculpturesClick() {
        navigate("feed-sculptures");
    }

    @FXML
    private void onFeedPhotosClick() {
        navigate("feed-photos");
    }

    @FXML
    private void onFeedRecommendationsClick() {
        navigate("feed-recommandations");
    }

    @FXML
    private void onBibliothequeClick() {
        navigate("bibliotheque");
    }

    @FXML
    private void onMusiqueClick() {
        navigate("musique");
    }

    @FXML
    private void onThemeLight() {
        if (themeHandler != null) {
            themeHandler.accept(false);
        }
    }

    @FXML
    private void onThemeDark() {
        if (themeHandler != null) {
            themeHandler.accept(true);
        }
    }

    @FXML
    private void onNotificationsClick() {
        notificationsButton.setText("!!");
    }

    @FXML
    private void onSwitchToAdminView() {
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    @FXML
    private void onSwitchToArtistView() {
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    @FXML
    private void onSwitchToAmateurView() {
        navigate("edit-profile");
    }

    @FXML
    private void onLogoutClick() {
        MainFX.switchToLoginView();
    }

    private void navigate(String route) {
        if (navigationHandler != null) {
            navigationHandler.accept(route);
        }
    }

    private void switchScene(String fxmlPath, String stylesheetPath, String title) {
        Stage stage = (Stage) anchorButton.getScene().getWindow();
        try {
            FXMLLoader loader = new FXMLLoader(getClass().getResource(fxmlPath));
            Parent root = loader.load();
            Scene scene = new Scene(root);
            URL stylesheet = Objects.requireNonNull(getClass().getResource(stylesheetPath), "Missing stylesheet");
            scene.getStylesheets().add(stylesheet.toExternalForm());
            stage.setTitle(title);
            stage.setScene(scene);
            stage.show();
        } catch (IOException e) {
            throw new IllegalStateException("Failed to switch scene: " + fxmlPath, e);
        }
    }
}

/* Amateur front-office theme placeholders */
.amateur-root {
    -fx-background-color: #eaf3ff;
}

.amateur-shell {
    -fx-background-color: transparent;
}

.amateur-page-card {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 12;
}

.amateur-left-sidebar {
    -fx-background-color: transparent;
}
.amateur-root {
    -fx-font-family: "Segoe UI", Arial, sans-serif;
    -fx-background-color: #eaf3ff;
}

.amateur-root .label {
    -fx-text-fill: #2f3e52;
}

.amateur-root .scroll-pane,
.amateur-root .scroll-pane > .viewport,
.amateur-root .scroll-pane .content,
.amateur-shell,
.amateur-page-host,
.amateur-content-column {
    -fx-background-color: transparent;
}

.amateur-scroll {
    -fx-background: #eaf3ff;
    -fx-background-color: transparent;
}

.amateur-navbar {
    -fx-background-color: #f8f9fb;
    -fx-border-color: #d9dce3;
    -fx-border-width: 0 0 1 0;
}

.amateur-search-field {
    -fx-background-color: #f4f5f7;
    -fx-border-color: #c8cdd7;
    -fx-border-radius: 6;
    -fx-background-radius: 6;
    -fx-padding: 0 12 0 12;
    -fx-prompt-text-fill: #9aa3b2;
}

.amateur-root .button,
.amateur-root .menu-button,
.amateur-root .combo-box-base,
.amateur-root .date-picker,
.amateur-root .text-field,
.amateur-root .text-area {
    -fx-background-radius: 8;
    -fx-border-radius: 8;
}

.amateur-icon-button,
.amateur-nav-link,
.amateur-nav-menu,
.amateur-avatar-menu {
    -fx-background-color: #eef1f5;
    -fx-border-color: #d4d9e1;
    -fx-text-fill: #3b4250;
    -fx-font-weight: 700;
}

.amateur-nav-link.active,
.amateur-nav-menu.active {
    -fx-background-color: #ebedff;
    -fx-border-color: #bfc6ff;
    -fx-text-fill: #3d3bc2;
}

.amateur-page-card {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #e8ecf2;
    -fx-border-radius: 12;
    -fx-effect: dropshadow(gaussian, rgba(60, 60, 60, 0.07), 10, 0, 0, 2);
}

.amateur-events-page {
    -fx-background-color: transparent;
}

.amateur-events-hero,
.amateur-events-body {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #e8ecf2;
    -fx-border-radius: 12;
    -fx-effect: dropshadow(gaussian, rgba(60, 60, 60, 0.07), 10, 0, 0, 2);
}

.amateur-events-hero {
    -fx-padding: 18 24 18 24;
}

.amateur-events-body {
    -fx-padding: 0;
}

.amateur-search-field {
    -fx-background-color: #f7f9fc;
    -fx-border-color: #d6deea;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 10 12 10 12;
    -fx-prompt-text-fill: #9aa3b2;
}

.amateur-search-button,
.amateur-primary-pill {
    -fx-background-color: #3d3bc2;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 8;
}

.amateur-primary-pill {
    -fx-padding: 8 14 8 14;
}

.amateur-search-button {
    -fx-padding: 8 16 8 16;
}

.amateur-category-tabs {
    -fx-padding: 6 0 0 0;
    -fx-border-color: transparent transparent #e2e8f0 transparent;
    -fx-border-width: 0 0 1 0;
}

.amateur-tab-button {
    -fx-background-color: transparent;
    -fx-text-fill: #5b6d86;
    -fx-font-weight: 700;
    -fx-padding: 7 12 7 12;
    -fx-background-radius: 999;
    -fx-border-radius: 999;
    -fx-border-color: transparent;
    -fx-border-width: 1;
    -fx-cursor: hand;
}

.amateur-tab-button:hover {
    -fx-background-color: #f3f6ff;
    -fx-text-fill: #33455f;
}

.amateur-tab-button.active {
    -fx-text-fill: #2f349a;
    -fx-background-color: #edf1ff;
    -fx-border-color: #cfd8fb;
}



.amateur-events-scroll,
.amateur-events-scroll > .viewport {
    -fx-background-color: transparent;
}

.amateur-events-flow {
    -fx-background-color: transparent;
}

.amateur-event-card {
    -fx-background-color: #ffffff;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 14;
    -fx-background-radius: 14;
    -fx-effect: dropshadow(gaussian, rgba(60, 60, 60, 0.08), 8, 0, 0, 2);
    -fx-cursor: hand;
}

.amateur-event-card:hover {
    -fx-border-color: #cfd8fb;
    -fx-effect: dropshadow(gaussian, rgba(61, 59, 194, 0.20), 16, 0.2, 0, 4);
}

.amateur-event-cover {
    -fx-background-color: #f3f4f6;
    -fx-background-radius: 10;
    -fx-border-radius: 10;
}

.amateur-event-cover .image-view {
    -fx-background-radius: 10;
}

.amateur-event-badge {
    -fx-background-color: rgba(17, 24, 39, 0.75);
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-padding: 5 10 5 10;
    -fx-background-radius: 999;
    -fx-font-size: 12px;
}

.amateur-event-badge-exposition {
    -fx-background-color: rgba(255, 255, 255, 0.94);
    -fx-border-color: #d6dfec;
    -fx-border-width: 1;
    -fx-text-fill: #1f2d3d;
}

.amateur-event-badge-concert {
    -fx-background-color: linear-gradient(to right, #1d4ed8, #2563eb);
}

.amateur-event-badge-spectacle {
    -fx-background-color: linear-gradient(to right, #5b21b6, #7c3aed);
}

.amateur-event-badge-conference {
    -fx-background-color: linear-gradient(to right, #0f766e, #14b8a6);
}

.amateur-details-chip {
    -fx-background-color: transparent;
    -fx-border-color: #d0d7e2;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-min-width: 42;
    -fx-min-height: 32;
}

.amateur-event-title {
    -fx-font-size: 17px;
    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.amateur-event-meta {
    -fx-font-size: 12px;
    -fx-text-fill: #94a3b8;
}

.amateur-event-status {
    -fx-font-size: 13px;
    -fx-text-fill: #9ca3af;
}

.amateur-event-price {
    -fx-font-size: 16px;
    -fx-font-weight: 700;
    -fx-text-fill: #5a6478;
}

.amateur-event-description {
    -fx-font-size: 13px;
