}

.avatar-menu:showing {
    -fx-background-color: #e1e7f3;
    -fx-border-color: #bcc6d8;
}

.avatar-menu > .arrow-button,
.avatar-menu > .arrow-button > .arrow {
    -fx-padding: 0;
    -fx-background-insets: 0;
    -fx-background-color: transparent;
}

.context-menu .menu-item.avatar-dropdown-item {
